// =============================================================================
// Fixture-specific type definitions (match JSON fixture format, allowing null)
// =============================================================================

export interface RepoWithStatus {
  id: string;
  working_path: string;
  upstream_url: string;
  gate_path: string;
  created_at: number;
  pending_runs: number;
  last_sync?: number | null;
  gate_healthy: boolean;
}

export interface RunInfo {
  id: string;
  status: string;
  branch: string;
  current_step?: string | null;
  workflow_file?: string;
  workflow_name?: string;
  created_at: number;
  updated_at: number;
  completed_at?: number | null;
}

export interface JobResultInfo {
  id: string;
  job_key: string;
  name?: string | null;
  status: string;
  job_order: number;
  started_at?: number | null;
  completed_at?: number | null;
  error?: string | null;
}

export interface StepResultInfo {
  id: string;
  job_id?: string;
  job_key?: string;
  step: string;
  status: string;
  exit_code?: number | null;
  duration_ms?: number | null;
  error?: string | null;
  started_at?: number | null;
  completed_at?: number | null;
}

export interface ArtifactInfo {
  name: string;
  path: string;
  artifact_type: string;
  size_bytes: number;
  created_at: number;
}

export interface RunDetailInfo {
  id: string;
  repo_id: string;
  status: string;
  branch?: string;
  base_sha?: string;
  head_sha?: string;
  current_step?: string | null;
  workflow_file?: string;
  workflow_name?: string;
  ref_updates?: Array<{ ref_name: string; old_sha: string; new_sha: string }>;
  error?: string | null;
  created_at: number;
  updated_at: number;
  completed_at?: number | null;
}

export interface GetRunDetailResult {
  run: RunDetailInfo;
  jobs: JobResultInfo[];
  step_results: StepResultInfo[];
  artifacts?: ArtifactInfo[];
}

export interface GetReposResult {
  repos: RepoWithStatus[];
}

export interface GetRunsResult {
  runs: RunInfo[];
}

export interface ReadArtifactResult {
  content: string;
  is_binary: boolean;
  total_size: number;
  bytes_read: number;
  offset: number;
}

export interface CommitDiffInfo {
  sha: string;
  message: string;
  author: string;
  timestamp: number;
  patch: string;
  files_changed: string[];
  additions: number;
  deletions: number;
}

export interface GetRunDiffResult {
  run_id: string;
  branch: string;
  base_sha: string;
  head_sha: string;
  patch: string;
  files_changed: string[];
  additions: number;
  deletions: number;
  commits?: CommitDiffInfo[];
}

