/**
 * Artifact content indexed by path.
 */
const artifactContentByPath: Record<string, ReadArtifactResult> = {};
for (const [hash, path] of Object.entries(artifactPathMappings)) {
  if (artifactContentByHash[hash]) {
    artifactContentByPath[path] = artifactContentByHash[hash];
  }
}

/**
 * Run diffs indexed by run ID.
 */
