// =============================================================================
// Helper functions
// =============================================================================

/**
 * Get all repos from the database export.
 */
export function getAllRepos(): RepoWithStatus[] {
  return allReposResult.repos;
}

/**
 * Get runs for a specific repo.
 */
export function getRunsForRepo(repoId: string): RunInfo[] {
  return runsByRepo[repoId]?.runs ?? [];
}

/**
 * Get all runs across all repos.
 */
export function getAllRuns(): RunInfo[] {
  const allRuns: RunInfo[] = [];
  for (const result of Object.values(runsByRepo)) {
    allRuns.push(...result.runs);
  }
  // Sort by created_at descending (most recent first)
  return allRuns.sort((a, b) => b.created_at - a.created_at);
}

/**
 * Find run detail by ID.
 */
export function findRunDetail(runId: string): GetRunDetailResult | null {
  return runDetails[runId] ?? null;
}

/**
 * Read artifact content by path.
 */
export function readArtifact(artifactPath: string, offset?: number, limit?: number): ReadArtifactResult | null {
  const result = artifactContentByPath[artifactPath];
  if (!result) {
    return null;
  }

  const readOffset = offset ?? 0;
  if (readOffset === 0 && !limit) {
    return result;
  }

  // Handle offset and limit
  const content = limit ? result.content.slice(readOffset, readOffset + limit) : result.content.slice(readOffset);

  return {
    content,
    is_binary: result.is_binary,
    total_size: result.total_size,
    bytes_read: content.length,
    offset: readOffset,
  };
}

/**
 * Get run diff by run ID.
 */
export function getRunDiff(runId: string): GetRunDiffResult | null {
  return runDiffs[runId] ?? null;
}
